import jwt
import datetime
import hashlib
import base64

SECRET_KEY = 'your_secret_key'
ALGORITHM = 'HS256'

def generate_token(user_id, role):
    payload = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),  # token expiry time
        'iat': datetime.datetime.utcnow(),  # token issued at
        'user_id': user_id,
        'role': role
    }

    encoded_payload = jwt.encode(
        payload, SECRET_KEY, algorithm=ALGORITHM)

    return encoded_payload.decode('utf-8')